-- Additive service-owned schema for integration-proxy-service.
CREATE TABLE IF NOT EXISTS integration_proxy_records (id UUID PRIMARY KEY, resource TEXT NOT NULL, payload JSONB NOT NULL, version INTEGER NOT NULL DEFAULT 1, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS integration_proxy_vpn_clients (id UUID PRIMARY KEY, common_name TEXT NOT NULL, real_address TEXT NOT NULL DEFAULT '', virtual_address TEXT NOT NULL DEFAULT '', bytes_received BIGINT NOT NULL DEFAULT 0, bytes_sent BIGINT NOT NULL DEFAULT 0, connected_since TIMESTAMPTZ, disconnected_at TIMESTAMPTZ, node TEXT NOT NULL DEFAULT '', status TEXT NOT NULL DEFAULT 'connected', payload JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS integration_proxy_vpn_usage_sessions (id UUID PRIMARY KEY, username TEXT NOT NULL, node TEXT NOT NULL DEFAULT '', virtual_address TEXT NOT NULL DEFAULT '', connected_since TIMESTAMPTZ NOT NULL, disconnected_at TIMESTAMPTZ, last_seen_at TIMESTAMPTZ NOT NULL, bytes_received BIGINT NOT NULL DEFAULT 0, bytes_sent BIGINT NOT NULL DEFAULT 0, payload JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE UNIQUE INDEX IF NOT EXISTS idx_integration_proxy_vpn_usage_session ON integration_proxy_vpn_usage_sessions (username, node, connected_since);
CREATE TABLE IF NOT EXISTS integration_proxy_outbox (event_id UUID PRIMARY KEY, event_name TEXT NOT NULL, trace_id TEXT NOT NULL, schema_version INTEGER NOT NULL, payload JSONB NOT NULL, occurred_at TIMESTAMPTZ NOT NULL);
CREATE TABLE IF NOT EXISTS integration_proxy_inbox (consumer TEXT NOT NULL, event_id UUID NOT NULL, processed_at TIMESTAMPTZ NOT NULL DEFAULT now(), PRIMARY KEY (consumer, event_id));
